//- _partial/pet.pug

style.
  /* 基础容器 */
  #pet-root {
    position: fixed;
    z-index: 9999;
    top: 0; left: 0;
    width: 0; height: 0;
    pointer-events: none;
    will-change: transform;
  }

  /* 核心内部容器 */
  .pet-inner {
    position: absolute;
    top: 0; left: 0;
    /* 强力描边，让轮廓清晰 */
    filter: 
      drop-shadow(2px 0 0 #fff)
      drop-shadow(-2px 0 0 #fff)
      drop-shadow(0 2px 0 #fff)
      drop-shadow(0 -2px 0 #fff);
    transform-origin: bottom center; 
    pointer-events: auto; 
    cursor: grab;
    touch-action: none; 
  }
  .pet-inner:active { cursor: grabbing; }

  /* 人物 */
  .pet-sprite {
    position: absolute;
    z-index: 30; 
    top: 0; left: 0;
    width: 100%; height: 100%;
    background-repeat: no-repeat;
    background-size: contain; 
    background-position: bottom center;
    image-rendering: pixelated;
  }

  /* 头发 */
  #pet-hair-canvas {
    position: absolute;
    z-index: 20; 
    top: 0; left: 0;
    pointer-events: none;
    /* 保持像素化风格，或者根据喜好去掉这行使其平滑 */
    image-rendering: pixelated;
  }

  /* 光环 */
  .pet-halo {
    position: absolute;
    z-index: 10;
    background-image: url('/images/pet/halo.png');
    background-size: contain;
    background-repeat: no-repeat;
