## 单链表的删除

原理: 先找到要删除节点的前置节点,用指针记录要删除的节点,通过修改前置节点的后继结点实现删除,释放删除节点的内存空间



```c
//删除节点
int deleteNode(Node *L,int pos){
	//要删除节点的前驱
	Node*p=L;
	int i=0;
	//遍历链表找到要删除节点的前驱
	while(i<pos-1){
		p=p->next;
		i++;
		if(p==NULL){
			return 0;
		}
	}
	if(p->next==NULL){
		printf("要删除的位置错误\n");
		return 0;
	}
	//q指向要删除的节点
	Node *q=p->next;
	//让要删除节点的前驱指向要删除节点的后继
	p->next=q->next;
	//释放要删除节点的内存空间
	free(q);
	return 1;
}

int main(){
	Node *list=initList();
	//得到当前尾节点
	Node *tail=get_tail(list);
	//每次在尾节点位置插入数据后更新尾节点的位置
	tail=insertTail(tail,10);
	tail=insertTail(tail,20);
	tail=insertTail(tail,30);
	//插入前
	listNode(list);
	//插入节点
	insertNode(list,2,15);
	//插入后
	listNode(list);
	//删除
	deleteNode(list,2);
	//删除后
	listNode(list);
	return 0;
}
