### 指针与函数

同样的,指针在函数里使用也是及其广泛的,这里我们就以最经典的swap 交换函数为例

```c
#include<stdio.h>
//void swap(int a,int b){
//	int temp;
//	temp=a;
//	a=b;
//	b=temp;
//	printf("交换后%d %d",a,b);
//}

void swap(int *a,int *b){
	int temp;
	temp=*a;
	*a=*b;
	*b=temp;
	printf("交换后%d %d",*a,*b);

}
int main(){
	int m;
	int n;
	printf("m值为:");
	scanf("%d",&m);
	printf("\nn值为:");
	scanf("%d",&n);
//	swap(m,n);
	swap(&m,&n);
	printf("\n交换前%d %d",m,n);
	return 0;
}
```

